-- =====================================================================
-- LP Development - Seed full (generado desde Excel inicial)
-- 14 empresas · 35 proyectos · 212 empleados
-- =====================================================================

-- 1) Empresas
on conflict (id) do nothing;

-- 2) Política por defecto en cada empresa (basada en Código de Trabajo de Panamá)
on conflict do nothing;

-- 3) Proyectos
create table if not exists projects (
  id          uuid primary key default uuid_generate_v4(),
  company_id  uuid not null references companies(id) on delete cascade,
  code        text,
  name        text not null,
  is_active   boolean not null default true,
  created_at  timestamptz not null default now()
);
alter table employees add column if not exists project_id uuid references projects(id);
alter table employees add column if not exists preferred_vacation_month text;

on conflict (id) do nothing;

-- 4) Empleados
on conflict do nothing;

-- 5) Balances iniciales basados en 'Dias Pendientes' del archivo histórico
--    Para días positivos: accrued = días pendientes, used = 0 (saldo acumulado pendiente)
--    Para días negativos: accrued = 0, used = |valor| (sobregiro - tomaron más de lo causado)
on conflict do nothing;
